
'use client';

import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Check, Star, X } from "lucide-react";
import Link from "next/link";
import { listings } from "@/lib/mock-data";
import { useState } from "react";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Review } from "@/lib/types";
import { useToast } from "@/hooks/use-toast";


const initialReviews = listings.flatMap(l => l.reviews.map(r => ({ ...r, listingName: l.name, listingId: l.id })));

type ReviewWithListing = (typeof initialReviews)[0];

export default function ContentModerationPage() {
    const [reviews, setReviews] = useState<ReviewWithListing[]>(initialReviews);
    const { toast } = useToast();
    
    const handleModerate = (reviewId: number, action: 'approved' | 'rejected') => {
        setReviews(prev => prev.filter(r => r.review_id !== reviewId));
        toast({
            title: `Review ${action}`,
            description: `The review has been ${action}.`
        })
    }

    return (
        <>
            <header className="mb-8">
                <h1 className="text-4xl font-bold font-headline">Content Moderation</h1>
                <p className="text-muted-foreground mt-2">
                    Review user-submitted content.
                </p>
            </header>

            <Card>
                <CardHeader>
                    <CardTitle>Pending Reviews</CardTitle>
                    <CardDescription>{reviews.length} reviews to moderate.</CardDescription>
                </CardHeader>
                <CardContent>
                   <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead>Author</TableHead>
                                <TableHead>Listing</TableHead>
                                <TableHead>Comment</TableHead>
                                <TableHead>Rating</TableHead>
                                <TableHead className="text-right">Actions</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {reviews.map(review => (
                                <ReviewRow key={review.review_id} review={review} onModerate={handleModerate} />
                            ))}
                        </TableBody>
                   </Table>
                </CardContent>
            </Card>
        </>
    );
}

function ReviewRow({ review, onModerate }: { review: ReviewWithListing, onModerate: (reviewId: number, action: 'approved' | 'rejected') => void }) {
     return (
        <Dialog>
            <DialogTrigger asChild>
                <TableRow className="cursor-pointer">
                    <TableCell>{review.user.name}</TableCell>
                    <TableCell>
                        <Link href={`/listings/${review.listing_id}`} className="hover:underline" onClick={(e) => e.stopPropagation()}>{review.listingName}</Link>
                    </TableCell>
                    <TableCell>
                        <p className="truncate max-w-xs">{review.comment}</p>
                    </TableCell>
                    <TableCell>
                        <Badge className="flex items-center gap-1 w-fit">
                            <span>{review.rating}</span>
                            <Star className="h-3 w-3" />
                        </Badge>
                    </TableCell>
                    <TableCell className="text-right">
                        <div className="flex justify-end gap-2" onClick={(e) => e.stopPropagation()}>
                            <Button variant="ghost" size="icon" className="text-green-500 hover:text-green-600" onClick={() => onModerate(review.review_id, 'approved')}><Check className="h-4 w-4" /></Button>
                            <Button variant="ghost" size="icon" className="text-destructive hover:text-destructive" onClick={() => onModerate(review.review_id, 'rejected')}><X className="h-4 w-4"/></Button>
                        </div>
                    </TableCell>
                </TableRow>
            </DialogTrigger>
            <DialogContent>
                <DialogHeader>
                    <DialogTitle>Review Details</DialogTitle>
                    <DialogDescription>Review submitted on {new Date(review.created_at).toLocaleDateString()}</DialogDescription>
                </DialogHeader>
                 <div className="space-y-4 py-4">
                    <div className="flex items-start gap-4">
                        <Avatar>
                            <AvatarImage src={review.user.avatar} alt={review.user.name} data-ai-hint="person" />
                            <AvatarFallback>{review.user.name.charAt(0)}</AvatarFallback>
                        </Avatar>
                        <div className="flex-1">
                            <p className="font-semibold">{review.user.name}</p>
                            <p className="text-sm text-muted-foreground">Review for <Link href={`/listings/${review.listing_id}`} className="underline hover:text-primary">{review.listingName}</Link></p>
                        </div>
                         <div className="flex items-center gap-1">
                            {[...Array(5)].map((_, i) => (
                                <Star key={i} className={`h-5 w-5 ${i < review.rating ? 'text-primary fill-primary' : 'text-muted-foreground/30'}`}/>
                            ))}
                        </div>
                    </div>
                     <Card className="bg-muted/50 p-4">
                        <p className="text-foreground">{review.comment}</p>
                     </Card>
                 </div>
                <DialogFooter>
                    <Button variant="outline" className="text-destructive hover:text-destructive" onClick={() => onModerate(review.review_id, 'rejected')}>
                        <X className="mr-2 h-4 w-4" />
                        Reject
                    </Button>
                    <Button className="bg-green-600 hover:bg-green-700 text-white" onClick={() => onModerate(review.review_id, 'approved')}>
                        <Check className="mr-2 h-4 w-4" />
                        Approve
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
     )
}
